// Le widget CRM envoie soit :
// - une action individuelle : { type: 'action_email' | 'action_relance' | 'action_send_contract', compte, contact, email, subject, body }
// - une action groupée : { type: 'bulk_email' | 'bulk_relance', recipients: [ { email, contact, compte, subject, body }, ... ] }
// On normalise les deux cas en une liste d'items, 1 item = 1 e-mail à envoyer.
const input = $input.first().json;
const payload = input.body !== undefined ? input.body : input;

let rows;
if (Array.isArray(payload.recipients)) {
  rows = payload.recipients;
} else {
  rows = [payload];
}

return rows
  .filter(r => r && r.email)
  .map(r => ({ json: r }));
